<template>
    <div class="my-popups">
         <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Bill To Customer Detail') }} </h4>
                        <button type="button" class="close" v-on:click="CloseBAC">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                      <dynamic-form ref="AddForm" :schema="FormSchema" :buttons="buttons" v-on:OnSubmit="SubmitData">
                        <template v-slot:tgslot-BAC_ID="{data}" >
                       
               <div class="input-group">
  <!-- AUTO BAC (readonly) -->
  <input
    v-if="isAutoBAC"
    id="AutoBACID"
    class="form-control"
    type="text"
    :value="autoBACValue"
    readonly
  />

  <!-- MANUAL BAC -->
  <input
    v-else
    id="txtBAC"
    class="form-control"
    type="text"
    v-model="manualBACValue"
    :class="{ 'input-validation-error': hasBACError }"
  />

  <div class="input-group-append">
    <span class="input-group-text">
      <a
        href="javascript:;"
        @click="toggleBACMode"
        :title="bacTooltip"
      >
        <i class="fa fa-pencil text-success font-18"></i>
      </a>
    </span>
  </div>
</div>





                                                                                
                          
                          </template>
                      </dynamic-form>                      
                    </div>   
                </div>
            </div>
        </div>        
    </div>
</template>
<script>
import DataService from "@/services/DataService";

export default {
  props: {
    clientId: Number,
    bacId: Number
  },
  data() {
    return {
       isAutoBAC: true,              // ModeAutoBAC
    autoBACValue: "",
    manualBACValue: "",
    recSource: "AUTO_BAC_ID",
    hasBACError: false,
      isLoading:false,
        FormSchema: [{
                layoutType: "double",
                Data: [
                  {
                    astype: "TextField",
                    label: this.$t('Invoice Grouping ID'),
                    name: "DIVISION_ID",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
                
                {
                    astype: "SelectField",
                    label: this.$t('Database ID'),
                    name: "Database_ID",
                    value: "",
                    placeholder: "",
                    config: {
                        options: []
                        //onChange: this.GetSubCategoryDDL
                    },
                    validationRules: {
                        "required": false
                    },
                },
                {
                    astype: "TextField",
                    label: this.$t('Bill To Customer Name'),
                    name: "BAC_NAME",
                    value: "",
                    placeholder: "",
                    validationRules: {
                        "required": true
                    },
                    disabled: false,
                },
                {
                    astype: "SlotField",
                    label: this.$t('Bill To Customer ID'),
                    name: "BAC_ID",
                    value: "",
                    placeholder: "",
                    validationRules: {
                        "required": true
                    },
                    disabled: false,
                    
  
                },
                {
                    astype: "TextField",
                    label: this.$t('FirstName'),
                    name: "CONTACT_FIRST",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
                {
                    astype: "TextField",
                    label: this.$t('LastName'),
                    name: "CONTACT_LAST",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
                {
                    astype: "TextField",
                    label: this.$t('Address1'),
                    name: "ADDRESS1",
                    value: "",
                    placeholder: "",
                    validationRules: {
                        "required": true
                    },
                    disabled: false,
                },
                {
                    astype: "TextField",
                    label: this.$t('Address2'),
                    name: "ADDRESS2",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
                {
                    astype: "TextField",
                    label: this.$t('City'),
                    name: "CITY",
                    value: "",
                    placeholder: "",
                    validationRules: {
                        "required": true
                    },
                    disabled: false,
                },
                {
                    astype: "SelectField",
                    label: this.$t('State'),
                    name: "STATE",
                    value: "",
                    placeholder: "",
                    config: {
                        options: []
                        //onChange: this.GetSubCategoryDDL
                    },
                    validationRules: {
                        "required": true
                    },
                },
                {
                    astype: "TextField",
                    label: this.$t('ZipCode'),
                    name: "ZIPCODE",
                    value: "",
                    placeholder: "",
                    validationRules: {
                        "required": true
                    },
                    disabled: false,
                },
                {
                    astype: "TextField",
                    label: this.$t('Business Entity Alternate Name'),
                    name: "BUSINESS_ENTITY_ALTERNATE_NAME",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
                {
  astype: "TextField",
  label: this.$t("AreaCode"),
  name: "AREA_CODE",
  value: "",
  placeholder: "",
  //helpText: this.$t("OnlyNumberXIsAllowed", { value: 3 }),
  required: true,
  allowOnly: "3",
  maxLength: 1,   // max 1 character 
},

                {
                    astype: "TextField",
                    label: this.$t('PhoneNumber'),
                    name: "CONTACT_BUSINESS_PHONE",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
                {
                    astype: "TextField",
                    label: this.$t('Email'),
                    name: "EMAIL",
                    value: "",
                    placeholder: "",
                    
                    disabled: false,
                },
              
                ]
            },
            
            
            ],
            buttons: [
              
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Cancel",
                onClick: this.CloseBAC,
            },
            ],
    }
  },

  created: async function () {
    //debugger;
      this.CompanyId = this.GetUserInfo.CompanyId;
        this.user_Id = this.GetUserInfo.ID;
      await this.getDatabaseList('DATABASE_LIST');
      await this.getDropdownList('UTILITY_STATE_LIST_BY_COUNTRY_ID');
        this.GetBACDetails();
  },

  methods: {
    toggleBACMode() {
      debugger;
    this.isAutoBAC = !this.isAutoBAC;

    if (!this.isAutoBAC) {
      // Switch to MANUAL
      this.recSource = "MANUAL_BAC_ID";
    } else {
      // Switch back to AUTO
      this.recSource = "AUTO_BAC_ID";
      this.hasBACError = false;
      this.manualBACValue = this.manualBACValue;
    }
  },
   
    getDropdownList: async function(type) {
       
            var vm = this;
             this.isLoading = true;
            let Url='';
          
            Url = `id=&moduleName=Billing&type=${type}&search=&refId=223`
          
            await DataService.GetDDLData(Url).then(response => {
                if (response.data != '' && response.data != null) {
                    const options = response.data.DATA.map(item => ({
        value: item.value,      // MUST match GetBACDetails value
        name: item.name
      }));
       // Bind options to SelectField
      this.setSelectOptions("STATE", options);

               this.isLoading = false;         
                }

            })
        },
    getDatabaseList: async function(type) {
            var vm = this;
            this.isLoading = true; 
            let Url = `id=&moduleName=Billing&type=${type}&search=&refId=`
            await DataService.GetDDLData(Url).then(response => {
              ///debugger;
                if (response.data != '' && response.data != null) {
                    if(type == 'DATABASE_LIST'){
                       
                        const options = response.data.DATA.map(item => ({
        value: item.value,      // MUST match GetBACDetails value
        name: item.name
      }));
       // Bind options to SelectField
      this.setSelectOptions("Database_ID", options);
      this.isLoading = false; 
                    }
                    
                }

            })
        },
    CloseBAC(){
            var ths =this;
            ths.$emit('CloseBAC');
        },
    setFieldValue(fieldName, value) {
      //debugger;
    this.FormSchema[0].Data.forEach(field => {
      if (field.name === fieldName) {
        field.value = value ?? "";
      }
    });
  },

  setSelectOptions(fieldName, options) {
    this.FormSchema[0].Data.forEach(field => {
      if (field.name === fieldName) {
        field.config.options = options;
      }
    });
  },
async GetBACDetails() {
 //debugger;
  this.isLoading = true;
  const params = `clientBacId=${this.bacId}`;
  const response = await DataService.GetBACById(params);
//debugger;
  if (!response || !response.data) return;

  const data = response.data;



  // Text fields
  this.autoBACValue=data[0].BAC_ID;
  this.manualBACValue=data[0].BAC_ID; 
  this.setFieldValue("DIVISION_ID", data[0].BE_DIVISION_ID);
  this.setFieldValue("BAC_NAME", data[0].BAC_NAME);
  this.setFieldValue("BAC_ID", data[0].BAC_ID);
  this.setFieldValue("CONTACT_FIRST", data[0].CONTACT_FIRST);
  this.setFieldValue("CONTACT_LAST", data[0].CONTACT_LAST);
  this.setFieldValue("ADDRESS1", data[0].ADDRESS1);
  this.setFieldValue("ADDRESS2", data[0].ADDRESS2);
  this.setFieldValue("CITY", data[0].CITY);
  this.setFieldValue("ZIPCODE", data[0].ZIPCODE);
  this.setFieldValue(
    "BUSINESS_ENTITY_ALTERNATE_NAME",
    data[0].BUSINESS_ENTITY_ALTERNATE_NAME
  );
  this.setFieldValue("AREA_CODE", data[0].AREA_CODE);
  this.setFieldValue(
    "CONTACT_BUSINESS_PHONE",
    data[0].CONTACT_BUSINESS_PHONE
  );
  this.setFieldValue("EMAIL", data[0].EMAIL);

  // Select fields (value only)
  this.setFieldValue("Database_ID", data[0].DATABASE_ID);
  this.setFieldValue("STATE", data[0].STATE);
   this.isLoading = false;
},


   async SubmitData() {},
    

    // close() {
    //   this.$emit("close");
    // }
  }
};
</script>
